+    fn seal_round_trip() {
+        let session_id = MeshSessionId(SESSION_ID_BYTES);
+        let plaintext = b"fcpc payload bytes";
+        let frame = FcpcFrame::seal(session_id, 42, FcpcFrameFlags::default(), plaintext, &K_CTX)
